# Create a latency-based routing record — Route 53 automatically directs users
# to whichever region has the lowest latency from their location

aws route53 change-resource-record-sets \
  --hosted-zone-id Z1234567890ABC \
  --change-batch '{
    "Changes": [
      {
        "Action": "CREATE",
        "ResourceRecordSet": {
          "Name": "api.example.com",
          "Type": "A",
          "SetIdentifier": "us-east-1",
          "Region": "us-east-1",
          "TTL": 60,
          "ResourceRecords": [{"Value": "54.12.34.56"}]
        }
      },
      {
        "Action": "CREATE",
        "ResourceRecordSet": {
          "Name": "api.example.com",
          "Type": "A",
          "SetIdentifier": "ap-southeast-1",
          "Region": "ap-southeast-1",
          "TTL": 60,
          "ResourceRecords": [{"Value": "52.77.88.99"}]
        }
      }
    ]
  }'

{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Sid": "DenyNonEURegions",
      "Effect": "Deny",
      "Action": "*",
      "Resource": "*",
      "Condition": {
        "StringNotEquals": {
          "aws:RequestedRegion": [
            "eu-west-1",
            "eu-central-1",
            "eu-west-3",
            "eu-north-1",
            "eu-south-1",
            "eu-west-2"
          ]
        }
      }
    }
  ]
}
